export const byHandle = Object.fromEntries(products.map((p) => [p.handle, p]));
export function getProduct(h) { return byHandle[h]; }
export function getCollection(h) { return collections.find((c) => c.handle === h); }
export function collectionProducts(h) {
  const c = getCollection(h);
  return c ? c.productHandles.map((ph) => byHandle[ph]).filter(Boolean) : [];
}
